import{_ as e,c as n,o as s,ag as i}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"PACKMOL简介","description":"","frontmatter":{},"headers":[],"relativePath":"分子模拟/必备技能/Packmol.md","filePath":"分子模拟/必备技能/Packmol.md","lastUpdated":null}'),o={name:"分子模拟/必备技能/Packmol.md"};function l(c,a,p,t,d,r){return s(),n("div",null,a[0]||(a[0]=[i(`<h1 id="packmol简介" tabindex="-1">PACKMOL简介 <a class="header-anchor" href="#packmol简介" aria-label="Permalink to &quot;PACKMOL简介&quot;">​</a></h1><ul><li>Packmol是一个构建分子动力学模拟初始结构的工具, 构建分子动力学模拟初始模型的软件。</li><li>由Sánchez和Chomilier开发，依据设定的条件，在空间范围内填充分子，形成不同的体系，如球状、管状、层状等体系。能够保证短程相互作用斥力不会影响模拟。</li><li>#免费 #开源 #windows #linux</li><li>官网: <a href="https://m3g.github.io/packmol/" target="_blank" rel="noreferrer">PACKMOL</a></li><li><a href="https://mp.weixin.qq.com/s/y_0FbdWPj3BYVGzhoc9dWg" target="_blank" rel="noreferrer">packmol基础教程 (qq.com)</a></li><li><a href="http://sobereva.com/473" target="_blank" rel="noreferrer">Packmol的使用</a></li><li>Packmol程序通过设置inp文件控制结构生成</li><li>使用命令: <code>packmol &lt; xxx.inp</code></li></ul><h2 id="inp输入文件内容" tabindex="-1">.inp输入文件内容： <a class="header-anchor" href="#inp输入文件内容" aria-label="Permalink to &quot;.inp输入文件内容：&quot;">​</a></h2><div class="language-.inp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">.inp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tolerance 2.0           不同分子的原子间距不小于2Å</span></span>
<span class="line"><span>output test.pdb</span></span>
<span class="line"><span>filetype pdb</span></span>
<span class="line"><span>structure xxx1.pdb       分子结构</span></span>
<span class="line"><span>    number 111</span></span>
<span class="line"><span>    inside cube 0. 0. 0. 40.        空间规则：随机分布在最小坐标(0,0,0)最大最大坐标(40,40,40)的立方体内</span></span>
<span class="line"><span>end structure</span></span>
<span class="line"><span>structure xxx2.pdb</span></span>
<span class="line"><span>    inside cube 0. 0. 0. 20.</span></span>
<span class="line"><span>    atoms 9 10                      限制原子9，10的位置</span></span>
<span class="line"><span>        inside box 0. 0. 15. 20. 20. 20.</span></span>
<span class="line"><span>    end atoms</span></span>
<span class="line"><span>end structure</span></span></code></pre></div><h2 id="空间约束规则" tabindex="-1">空间约束规则 <a class="header-anchor" href="#空间约束规则" aria-label="Permalink to &quot;空间约束规则&quot;">​</a></h2><ul><li>有几种类型的约束既可以应用于整个分子，也可以应用于分子的一部分。这些约束定义了分子必须位于溶液中的空间区域。可以以这种方式构建非常有序的系统。约束条件包括： 1.固定分子<code>fixed x y z a b g</code> 2.放置在立方体内<code>inside cube xmin ymin zmin d</code> 3.放置在立方体外<code>outside cube xmin ymin zmin d</code> 4.放置在盒子内<code>inside box xmin ymin zmin xmax ymax zmax</code> 5.放置在盒子外<code>outside box xmin ymin zmin xmax ymax zmax</code> 6.放置在球内/外: (x−a)^2+(y−b)^2+(z−c)^2−d^2=0 <code>inside sphere a b c d</code><br><code>outside sphere a b c d</code> 7.椭球 <code>inside/outside ellipsoid a1 b1 c1 a2 b2 c2 d</code> 8.above (or below) plane: ax+by+cz−d=0 <code>above plane 2.5 3.2 1.2 6.2</code><br><code>below plane 2.5 3.2 1.2 6.2</code> 9.inside (or outside) cylinder圆柱体: p=(a1,b1,c1)+t×(a2,b2,c2) <code>inside cylinder a1 b1 c1 a2 b2 c2 d l</code><code>outside cylinder a1 b1 c1 a2 b2 c2 d l</code> 10.Constrain rotations: 限制每种类型的所有分子的旋转，使它们在空间中具有一些平均取向。 <code>constrain_rotation x 180. 20.</code><br><code>constrain_rotation y 180. 20.</code><br><code>constrain_rotation z 180. 20.</code> 11.over (or below) xygauss (gaussian surface) <code>over xygauss a1 b1 a2 b2 c h</code><code>below xygauss a1 b1 a2 b2 c h</code> 12.设置不同分子间原子半径</li></ul><div class="language-.inp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">.inp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>structure water.pdb</span></span>
<span class="line"><span>  number 500</span></span>
<span class="line"><span>  inside box 0. 0. 0. 30. 30. 30.</span></span>
<span class="line"><span>  radius 1.5           #原子的半径为 1.5Å，意味着分子内的距离为 3.0Å</span></span>
<span class="line"><span>end structure</span></span></code></pre></div><h2 id="周期性边界条件" tabindex="-1">周期性边界条件 <a class="header-anchor" href="#周期性边界条件" aria-label="Permalink to &quot;周期性边界条件&quot;">​</a></h2><p>如果您的系统在 100Å 盒子中模拟，则将分子约束在98Å盒子内，当构建带有 PBC 的实际模拟盒时，图像将彼此分开2Å。边界处将有一个空白空间，但随着能量最小化和平衡，这将很容易消失。</p><h2 id="溶剂化大分子" tabindex="-1">溶剂化大分子 <a class="header-anchor" href="#溶剂化大分子" aria-label="Permalink to &quot;溶剂化大分子&quot;">​</a></h2><ul><li><code>solvate.tcl PROTEIN.pdb</code>该脚本将创建一个名为 packmol_input.inp 的输入文件，包括框的大小和建议要使用的周期性边界条件尺寸</li><li><code>packmol &lt; packmol_input.inp</code>大分子将被 15Å 的水壳溶剂化，离子保持系统中性，生理NaCl浓度0.16M。</li><li><code>solvate.tcl structure.pdb -shell 15. -charge +5 -density 1.0 -i pack.inp -o solvated.pdb</code>残基电性：Arg and Lys as +1 and Glu and Asp as -1. -noions 不添加任何离子，只添加水</li></ul>`,11)]))}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
